// Generate a list of static imports for all Prism languages in "dependency order".
// Since esbuild cannot resolve dynamic requires, static imports via this generated file
// are necessary to bundle all languages.
// Unless dependency order is preserved, prism-cpp might be evaluated before prism-c
// causing Prism.languages.extend('c', ...) to fail, so we use prismjs's own dependency resolver.
const fs = require('fs');
const path = require('path');

const components = require('prismjs/components.js');
const getLoader = require('prismjs/dependencies');

const all = Object.keys(components.languages).filter((id) => id !== 'meta');

const order = [];
getLoader(components, all, []).load((id) => {
  if (id in components.languages) order.push(id);
});

const lines = [
  '// AUTO-GENERATED by scripts/gen-prism-imports.cjs — do not edit.',
  "// Load all Prism languages in dependency order (evaluating core first to prepare global.Prism).",
  "import 'prismjs';",
  ...order.map((id) => `import 'prismjs/components/prism-${id}';`),
  '',
].join('\n');

const outPath = path.join(__dirname, '..', 'src', 'prism-languages.generated.ts');
fs.writeFileSync(outPath, lines);
console.log(`Generated: ${path.relative(path.join(__dirname, '..'), outPath)} (${order.length} languages)`);
